#include <cstring>
#include <iostream>
#include <vector>
#include <utility>

class DynamicString {
public:
    // Constructor
    explicit DynamicString(const char* str = "")
        : size_(std::strlen(str)),
          data_(new char[size_ + 1]) {
        std::memcpy(data_, str, size_ + 1);
    }

    // Destructor
    ~DynamicString() { delete[] data_; }

    // Copy constructor (deep copy)
    DynamicString(const DynamicString& other)
        : size_(other.size_),
          data_(new char[other.size_ + 1]) {
        std::memcpy(data_, other.data_, size_ + 1);
    }

    // Copy assignment (copy-and-swap)
    DynamicString& operator=(DynamicString other) noexcept {
        swap(other); // other is a copy or a moved-from object
        return *this;
    }

    // Move constructor
    DynamicString(DynamicString&& other) noexcept
        : size_(other.size_),
          data_(other.data_) {
        other.data_ = nullptr;
        other.size_ = 0;
    }

    // Accessors
    const char* c_str() const { return data_ ? data_ : ""; }
    std::size_t size() const  { return size_; }

private:
    void swap(DynamicString& other) noexcept {
        std::swap(data_, other.data_);
        std::swap(size_, other.size_);
    }
    char* data_;
    std::size_t size_;
};

int main() {
    std::vector<DynamicString> v;
    v.reserve(1); // Force reallocation on push_back
    v.emplace_back("hello");
    v.emplace_back("world"); // Triggers move during reallocation

    DynamicString a("foo");
    DynamicString b = a;               // Copy constructor
    DynamicString c = std::move(a);    // Move constructor
    b = DynamicString("bar");          // Move assignment

    std::cout << b.c_str() << '\n';   // bar
    std::cout << c.c_str() << '\n';   // foo
    std::cout << v[0].c_str() << '\n'; // hello
    std::cout << v[1].c_str() << '\n'; // world
}

#include <vector>
#include <stdexcept>
