#include <iostream>

template<typename T>
class Stack {
    static_assert(
        std::is_copy_constructible_v<T> || std::is_move_constructible_v<T>,
        "Stack<T>: T must be copy or move constructible"
    );
public:
    void push(const T& val) { data_.push_back(val); }
    void push(T&& val)      { data_.push_back(std::move(val)); }

    void pop() {
        if (empty()) throw std::underflow_error("pop on empty stack");
        data_.pop_back();
    }

    const T& top() const {
        if (empty()) throw std::underflow_error("top on empty stack");
        return data_.back();
    }

    bool        empty() const { return data_.empty(); }
    std::size_t size()  const { return data_.size();  }

private:
    std::vector<T> data_;
};

// Only for arithmetic types
template<typename T>
std::enable_if_t<std::is_arithmetic_v<T>, T>
sum_stack(Stack<T> s) {
    T total{};
    while (!s.empty()) { total += s.top(); s.pop(); }
    return total;
}

int main() {
    Stack<int> s;
    s.push(10); s.push(20); s.push(30);
    std::cout << "Top: " << s.top() << '\n';
    std::cout << "Sum: " << sum_stack(s) << '\n';

    try {
        Stack<double> empty;
        empty.pop();
    } catch (const std::underflow_error& e) {
        std::cout << "Caught: " << e.what() << '\n';
    }
}

#include <queue>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <iostream>
#include <atomic>

template<typename T>
class BoundedQueue {
public:
    explicit BoundedQueue(std::size_t cap) : capacity_(cap) {}

    void push(T val) {
        std::unique_lock lock(mutex_);
        not_full_.wait(lock, [this] { return queue_.size() < capacity_; });
        queue_.push(std::move(val));
        not_empty_.notify_one();
    }

    T pop() {
        std::unique_lock lock(mutex_);
        not_empty_.wait(lock, [this] { return !queue_.empty(); });
        T val = std::move(queue_.front());
        queue_.pop();
        not_full_.notify_one();
        return val;
    }

    bool try_push(T val) {
        std::unique_lock lock(mutex_);
        if (queue_.size() >= capacity_) return false;
        queue_.push(std::move(val));
        not_empty_.notify_one();
        return true;
    }

    bool try_pop(T& out) {
        std::unique_lock lock(mutex_);
        if (queue_.empty()) return false;
        out = std::move(queue_.front());
        queue_.pop();
        not_full_.notify_one();
        return true;
    }

    std::size_t size()  const { std::unique_lock l(mutex_); return queue_.size(); }
    bool        empty() const { std::unique_lock l(mutex_); return queue_.empty(); }

private:
    mutable std::mutex         mutex_;
    std::condition_variable    not_full_;
    std::condition_variable    not_empty_;
    std::queue<T>              queue_;
    std::size_t                capacity_;
};

int main() {
    BoundedQueue<int> q(5);
    std::atomic<int> consumed{0};

    auto producer = [&](int start) {
        for (int i = start; i < start + 10; ++i)
            q.push(i);
    };

    auto consumer = [&] {
        while (consumed.fetch_add(1) < 20) {
            int v = q.pop();
            std::cout << v << ' ';
        }
    };

    std::vector<std::thread> threads;
    threads.emplace_back(producer, 0);
    threads.emplace_back(producer, 10);
    for (int i = 0; i < 3; ++i) threads.emplace_back(consumer);
    for (auto& t : threads) t.join();
    std::cout << '\n';
}

#include <memory>
#include <iostream>

struct Node {
    int value;
    std::shared_ptr<Node> next; // Owns the next node
    std::weak_ptr<Node>   prev; // Non-owning back-reference
                                // weak_ptr prevents cycle: if prev were shared_ptr,
                                // each node would keep adjacent nodes alive forever
    explicit Node(int v) : value(v) {
        std::cout << "Node(" << v << ") created\n";
    }
    ~Node() { std::cout << "Node(" << value << ") destroyed\n"; }
};

int main() {
    auto n1 = std::make_shared<Node>(1);
    auto n2 = std::make_shared<Node>(2);
    auto n3 = std::make_shared<Node>(3);

    // Forward links (owning)
    n1->next = n2;
    n2->next = n3;

    // Back links (non-owning, avoids cycle)
    n2->prev = n1;
    n3->prev = n2;

    // Traverse forward
    std::cout << "Forward: ";
    for (auto cur = n1; cur; cur = cur->next)
        std::cout << cur->value << ' ';
    std::cout << '\n';

    // Traverse backward from n3
    std::cout << "Backward: ";
    for (auto cur = n3; cur; cur = cur->prev.lock())
        std::cout << cur->value << ' ';
    std::cout << '\n';

    // n1, n2, n3 go out of scope — all nodes destroyed
}

#include <concepts>
#include <format>
#include <iostream>
#include <vector>
#include <algorithm>
#include <ranges>

// Concept: type can be printed via operator<<
template<typename T>
concept Printable = requires(std::ostream& os, const T& val) {
    { os << val } -> std::convertible_to<std::ostream&>;
};

// Constrained function template
template<std::ranges::range Container>
    requires Printable<std::ranges::range_value_t<Container>>
void print_all(const Container& c) {
    if constexpr (std::ranges::empty(c) == false) {
        for (const auto& elem : c)
            std::cout << std::format("{} ", elem);
        std::cout << '\n';
    } else {
        std::cout << "(empty)\n";
    }
}

struct Point {
    int x, y;
    auto operator<=>(const Point&) const = default; // All comparisons for free

    friend std::ostream& operator<<(std::ostream& os, const Point& p) {
        return os << std::format("({},{})", p.x, p.y);
    }
};

int main() {
    std::vector<Point> pts = {{3,1},{1,4},{1,5},{2,6},{5,3}};
    std::ranges::sort(pts);           // Uses operator<=> automatically
    print_all(pts);

    std::vector<int> nums = {5, 3, 8, 1, 9};
    std::ranges::sort(nums);
    print_all(nums);
}
